---货币类型
MoneyType = {
    Diamonds = 1,
    Golds = 2,
    Currency = 3
}

---货币图片映射表
local MoneyIcon = {
    [MoneyType.Diamonds] = "set:app_shop.json image:app_shop_diamonds_mods",
    [MoneyType.Golds] = "set:app_shop.json image:app_shop_gold",
    [MoneyType.Currency] = "set:jail_break.json image:jail_break_currency",
}

---是否需要支持现金支付(回平台充值)
local EnableRecharge = true

---注册货币类型和图片之间的映射关系
function registerMoneyIcon(type, icon)
    MoneyIcon[type] = icon
end

---根据货币类型获取货币图片(私有方法)
local function getMoneyIcon(type)
    return MoneyIcon[type] or ""
end

---弹出货币不足对话框
local function showLackOfMoneyDialog(needMoney, type)
    if EnableRecharge then
        CheckMoneyContent:setCurrencyInfo(getMoneyIcon(type), needMoney)
        if type == PayHelper.Diamonds then
            CheckMoneyContent:setContentText(Lang:getString("gui_need_back_platform_top_up"))
        else
            CheckMoneyContent:setContentText(Lang:getString("gui_dialog_tip_content_go_app_shop"))
        end
        local listener = function()
            if type == MoneyType.Diamonds then
                ClientHelper.onRecharge(1)
                GoRechargeEvent:invoke()
            else
                if GoAppShopEvent:invoke(type) then
                    RootGuiLayout.Instance():showAppShop(-1)
                end
            end
        end
        CustomDialog.builder()
                    .setTitleText("lack_of_money")
                    .setContentView(CheckMoneyContent)
                    .setRightClickListener(listener)
                    .show()
    else
        CustomDialog.builder()
                    .setContentText(Lang:getString("lack_of_money"))
                    .setLeftText(nil)
                    .show()
    end
end

PayHelper = {}

function PayHelper.disableRecharge()
    EnableRecharge = false
end

function PayHelper.isEnableRecharge()
    return EnableRecharge
end

---通用的校验货币是否足够的方法
---@type 货币类型
---@price 商品价格
---@callback 监听回调方法
function PayHelper.checkMoney(type, price, callback)
    local money = PlayerWallet.getMoneyByCoinId(type)
    if money < price then
        ---货币不足，去充值或购买
        showLackOfMoneyDialog(price - money, type)
        callback(false)
    else
        callback(true)
    end
end

---根据货币类型获取货币图片(公有方法)
function PayHelper.getMoneyIcon(type)
    return getMoneyIcon(type)
end